blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie dowiesz się, jaka jest różnica między rzeczownikami policzalnymi i niepoliczalnymi – jak je rozróżnić i poprawnie używać. liczyć:",
    "rules": [
        {
            "label": "Countable",
            "color": "emerald",
            "text": "<strong>Злічувані</strong> — можна порахувати:",
            "example": "jedno jabłko, dwa jabłka, trzy książki"
        },
        {
            "label": "Niepoliczalne",
            "color": "amber",
            "text": "<strong>Niepoliczalne</strong> — nie można policzyć:",
            "example": "woda, informacje, porady, muzyka"
        },
        {
            "label": "Artykuły",
            "color": "blue",
            "text": "<strong>Artykuły:</strong> a/an – tylko policzalne:",
            "example": "książka ✓ / woda ✗"
        }
    ]
}

{
    "title": "1. Co to są rzeczowniki policzalne i niepoliczalne?",
    "intro": "Rzeczowniki dzielą się na dwie kategorie:",
    "items": [
        {
            "label": "Policzalne",
            "title": "Policzalne",
            "subtitle": "Można policzyć, występują w liczbie pojedynczej i mnogiej (jabłko → jabłka)"
        },
        {
            "label": "Niepoliczalne",
            "title": "Niepoliczalne",
            "subtitle": "Nie można policzyć, nie ma liczby mnogiej (woda, muzyka)"
        },
        {
            "label": "Oba",
            "title": "Obie formy",
            "subtitle": "Niektóre rzeczowniki mogą występować jednocześnie (kurczak — kurczak / kurczak)"
        }
    ]
}

{
    "title": "2. Rzeczowniki policzalne ",
    "sections": [
        {
            "label": "Rzeczowniki policzalne",
            "color": "emerald",
            "description": "<strong>Rzeczowniki policzalne</strong> można policzyć. Występują w liczbie pojedynczej <strong>pojedynczej</strong> i <strong>liczbie mnogiej</strong>.",
            "examples": [
                {
                    "en": "jedna książka, dwie książki, trzy książki",
                    "ua": "jedna książka, dwie książki, trzy książki"
                },
                {
                    "en": "kot, kilka kotów, wiele kotów",
                    "ua": "kat, kilka kotów, wiele koty"
                },
                {
                    "en": "pomysł, długopis z wieloma pomysłami.",
                    "ua": "ідея, кілька ідей"
                }
            ]
        },
        {
            "label": "З артиклями a/an",
            "color": "sky",
            "description": "Злічувані іменники в однині вживаються з <strong>a/an</strong> або іншим визначником.",
            "examples": [
                {
                    "en": "I need a pen.",
                    "ua": "Мені потрібна ручка."
                },
                {
                    "en": "Ona jest inżynierem.",
                    "ua": "Ona jest inżynierem."
                },
                {
                    "en": "Daj mi książkę.",
                    "ua": "Daj mi książka."
                }
            ],
            "note": "❌ Nie jest możliwe: <em>Potrzebuję długopisu.</em> — bez przedimka jest niepoprawne!"
        },
        {
            "label": "Przykłady policzalne",
            "color": "amber",
            "description": "Typowe rzeczowniki policzalne:",
            "examples": [
                {
                    "en": "książka, długopis, stół, krzesło",
                    "ua": "książka, długopis, stół, krzesło"
                },
                {
                    "en": "jabłko, banan, jajko, kanapka",
                    "ua": "jabłko, banan, jajko, kanapka"
                },
                {
                    "en": "osoba, przyjaciel, uczeń, nauczyciel",
                    "ua": "osoba, przyjaciel, uczeń, nauczyciel"
                },
                {
                    "en": "pomysł, problem, pytanie, odpowiedź",
                    "ua": "pomysł, problem, pytanie, odpowiedź"
                }
            ]
        }
    ]
}

{
    "title": "3. Rzeczowniki niepoliczalne ",
    "sections": [
        {
            "label": "Rzeczowniki niepoliczalne",
            "color": "amber",
            "description": "<strong>Rzeczowniki niepoliczalne</strong> nie mogą być policzone. <strong>Nie mają liczby mnogiej</strong> i są używane z czasownikiem w liczbie pojedynczej.",
            "examples": [
                {
                    "en": "Woda jest ważna.",
                    "ua": "Woda jest ważna. (nie wody)"
                },
                {
                    "en": "Informacja jest przydatna.",
                    "ua": "Informacja jest przydatna. (nie informacje)"
                },
                {
                    "en": "Muzyka mnie uszczęśliwia.",
                    "ua": "Muzyka mnie uszczęśliwia."
                }
            ]
        },
        {
            "label": "Brak przedimka a/an",
            "color": "rose",
            "description": "Rzeczowniki niepoliczalne <strong>NIE są używane</strong> z rodzajnikami i/an.",
            "examples": [
                {
                    "en": "✓ Potrzebuję wody.",
                    "ua": "Potrzebuję wody."
                },
                {
                    "en": "✗ Potrzebuję wody.",
                    "ua": "(źle!)"
                },
                {
                    "en": "✓ Dała mi radę.",
                    "ua": "Dała mi porada.[[[CODX_13]]]✗ Dała mi radę: sok"
                },
                {
                    "en": "✗ She gave me an advice.",
                    "ua": "(неправильно!)"
                }
            ]
        },
        {
            "label": "Категорії незлічуваних",
            "color": "sky",
            "description": "Основні групи незлічуваних іменників:",
            "examples": [
                {
                    "en": "Liquids: water, milk, coffee, tea, juice",
                    "ua": "Рідини: вода, молоко, кава, чай, сік"
                },
                {
                    "en": "Materiały: drewno, plastik, szkło, papier",
                    "ua": "Materiały: drewno, plastik, szkło, papier"
                },
                {
                    "en": "Streszczenie: informacje, porady, aktualności, wiedza",
                    "ua": "Streszczenie: informacje, porady, aktualności, wiedza"
                },
                {
                    "en": "Masy spożywcze: ryż, pieczywo, cukier, sól, mięso",
                    "ua": "Żywność (masa): ryż, pieczywo, cukier, sól, mięso"
                }
            ]
        }
    ]
}

{
    "title": "4. Jak mierzyć rzeczowniki niepoliczalne",
    "sections": [
        {
            "label": "Jednostki miary",
            "color": "emerald",
            "description": "Do „liczenia” rzeczy niepoliczalnych używamy <strong>jednostek miary</strong>.",
            "examples": [
                {
                    "en": "szklanka wody",
                    "ua": "szklanka wody woda"
                },
                {
                    "en": "filiżanka kawy",
                    "ua": "filiżanka kawy"
                },
                {
                    "en": "butelka mleka",
                    "ua": "butelka mleka"
                },
                {
                    "en": "rada",
                    "ua": "rada (jedna)"
                }
            ]
        },
        {
            "label": "Typowe projekty",
            "color": "sky",
            "description": "Popularne metody pomiaru:",
            "examples": [
                {
                    "en": "kawałek: ciasta, papieru, wiadomości, mebli[[[CODX_5]]]sztuka/część: ciasto, papier, nowości, meble",
                    "ua": "шматок/частина: торта, паперу, новина, меблі"
                },
                {
                    "en": "kromka: chleba, pizzy, sera",
                    "ua": "kromka: chleba, pizzy, sera"
                },
                {
                    "en": "bochenek: chleba",
                    "ua": "bochenek chleba"
                },
                {
                    "en": "batonik: czekolada, mydło",
                    "ua": "batonik: czekolady, kawałek kochany"
                }
            ]
        },
        {
            "label": "trochę/trochę",
            "color": "amber",
            "description": "za nieokreśloną ilość:",
            "examples": [
                {
                    "en": "trochę wody, trochę informacji",
                    "ua": "trochę szczęścia, trochę pomóż"
                },
                {
                    "en": "a bit of luck, a bit of help",
                    "ua": "odrobina szczęścia, odrobina pomocy pomocy"
                },
                {
                    "en": "trochę cukru, trochę czasu",
                    "ua": "trochę cukru, trochę czasu"
                }
            ]
        }
    ]
}

{
    "title": "5. Kwantyfikatory",
    "sections": [
        {
            "label": "Tylko policzalne",
            "color": "emerald",
            "description": "Te słowa są używane <strong>tylko z policzalnymi</strong>:",
            "examples": [
                {
                    "en": "wiele książek, wielu przyjaciół",
                    "ua": "wiele książek, wielu przyjaciół"
                },
                {
                    "en": "kilka pytania",
                    "ua": "kilka pomysłów"
                },
                {
                    "en": "kilka osób (kilka - negatywnych)",
                    "ua": "kilka osób"
                },
                {
                    "en": "kilka pomysłów",
                    "ua": "kilka pomysłów"
                }
            ]
        },
        {
            "label": "Tylko niezliczone",
            "color": "amber",
            "description": "Te słowa są używane <strong>tylko w przypadku niepoliczalnych</strong>:",
            "examples": [
                {
                    "en": "dużo czasu, dużo pieniędzy",
                    "ua": "dużo czasu, dużo pieniędzy"
                },
                {
                    "en": "trochę wody",
                    "ua": "mała woda"
                },
                {
                    "en": "mała nadzieja (mała - negatywna)",
                    "ua": "mała nadzieja"
                }
            ]
        },
        {
            "label": "Obydwa typy",
            "color": "sky",
            "description": "Uniwersalne słowa na <strong>oba typy</strong>:",
            "examples": [
                {
                    "en": "kilka książek / trochę wody",
                    "ua": "dużo znajomych / dużo czasu"
                },
                {
                    "en": "any questions / any information",
                    "ua": "будь-які питання / будь-яка інформація"
                },
                {
                    "en": "a lot of friends / a lot of time",
                    "ua": "dużo znajomych / dużo czasu"
                },
                {
                    "en": "dużo ludzi / dużo pieniędzy",
                    "ua": "wiele osób / dużo czasu pieniądze"
                }
            ]
        }
    ]
}

{
    "title": "6. Tabela porównawcza",
    "intro": "Główne różnice między policzalnymi i niepoliczalnymi:",
    "rows": [
        {
            "en": "Forma liczby mnogiej",
            "ua": "Mnogość",
            "note": "Policzalne: książki ✓ / Niepoliczalne: wody ✗"
        },
        {
            "en": "A / An",
            "ua": "Artykuł a/an",
            "note": "Policzalne: książka ✓ / Niepoliczalne: woda ✗"
        },
        {
            "en": "Liczby",
            "ua": "Liczby",
            "note": "Policzalne: dwie książki ✓ / Niepoliczalne: dwie wody ✗"
        },
        {
            "en": "Wiele / Dużo Dowolne</strong> - uniwersalne dla obu typów!",
            "ua": "Багато",
            "note": "Countable: many ✓ / Uncountable: much ✓"
        },
        {
            "en": "Few / Little",
            "ua": "Мало",
            "note": "Countable: few ✓ / Uncountable: little ✓"
        }
    ],
    "warning": "📌 <strong>A lot of / Some / Any</strong> — універсальні для обох типів!"
}

{
    "title": "7. Rzeczowniki o podwójnym znaczeniu",
    "sections": [
        {
            "label": "Niepoliczalne",
            "color": "purple",
            "description": "Niektóre rzeczowniki mogą być <strong>policzalne LUB niepoliczalne</strong> i mieć różne znaczenie:",
            "examples": [
                {
                    "en": "kurczak (niepoliczalny) = mięso",
                    "ua": "kurczak (mięso)[[[CODX_1]]]kurczak (policzalny) = kubek dla ptaka"
                },
                {
                    "en": "a chicken (countable) = bird",
                    "ua": "курка (птах)"
                },
                {
                    "en": "coffee (uncountable) = drink",
                    "ua": "кава (напій)"
                },
                {
                    "en": "a coffee (countable) = a cup",
                    "ua": "filiżanka kawy"
                }
            ]
        },
        {
            "label": "Więcej przykładów",
            "color": "sky",
            "description": "Inne rzeczowniki o podwójnym znaczeniu:",
            "examples": [
                {
                    "en": "szkło (niepoliczalne) = materiał",
                    "ua": "szkło (materiał)"
                },
                {
                    "en": "szklanka (policzalne) = pojemnik",
                    "ua": "szkło (naczynia)"
                },
                {
                    "en": "papier (niepoliczalne) = materiał",
                    "ua": "papier (materiał)"
                },
                {
                    "en": "artykuł (policzalny) = dokument/gazeta",
                    "ua": "dokument/gazeta"
                }
            ]
        }
    ]
}

{
    "title": "8. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zbiór liczb nieprzeliczalnych.",
            "wrong": "Potrzebuję trochę informacji.",
            "right": "​​​​ <span class="font-mono">Potrzebuję trochę informacje.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Artykuł a/an z liczbami nieprzeliczalnymi.",
            "wrong": "Czy mogę dostać wodę?",
            "right": "​​​​​​​​ policzalnych."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Much зі злічуваними.",
            "wrong": "Jest ich wiele książki tutaj.",
            "right": " ✅ <span class="font-mono">Jest tu wiele książek.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Wiele z niepoliczalnymi.",
            "wrong": "Mam wiele pieniądze.",
            "right": "​​​​ <span class="font-mono">Mam dużo pieniędzy. / Mam dużo pieniędzy.</span>"
        }
    ]
}

{
    "title": "10. Ćwiczenie",
    "select_title": "Ćwiczenie 1. Określ rodzaj rzeczownika",
    "select_intro": "Określ, czy rzeczownik jest policzalny (C), czy niepoliczalny (U).",
    "selects": [
        {
            "label": "woda (C/U)",
            "prompt": "Jaki typ? "
        },
        {
            "label": "książka (C/U)",
            "prompt": "Jaki typ?"
        },
        {
            "label": "informacje (C/U)",
            "prompt": "Jaki typ?"
        },
        {
            "label": "jabłko (C/U)",
            "prompt": "Jaki typ?"
        }
    ],
    "options": [
        "Policzalne",
        "Niepoliczalne"
    ],
    "input_title": "Ćwiczenie 2. Wybierz wiele lub dużo",
    "input_intro": "Wpisz w puste miejsca wiele lub dużo.",
    "inputs": [
        {
            "before": "Jak ___ książki robisz masz?",
            "after": " →"
        },
        {
            "before": "Nie mam ___ czasu.",
            "after": " →"
        },
        {
            "before": "Jest tu ___ osób.",
            "after": " →"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Poprawianie błędów",
    "rephrase_intro": "Znajdź i popraw błąd w zdaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Potrzebuję porady.",
            "example_target": "Potrzebuję porady. / Potrzebuję rady."
        },
        {
            "original": "1. Przekazała mi wiele informacji.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Czy mogę zjeść nabiał? Ilość",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші сторінки з категорії Іменники, артиклі та кількість",
    "items": [
        {
            "label": "Countable vs Uncountable — Злічувані / незлічувані",
            "current": true
        },
        {
            "label": "Articles — Артиклі a/an/the",
            "current": false
        },
        {
            "label": "Some / Any — Кількість",
            "current": false
        },
        {
            "label": "Dużo / Wiele / Dużo",
            "current": false
        }
    ]
}
